def match_route(route, remaining_parts):
    # If route is a dict, try common route keys
    if isinstance(route, dict):
        # Direct path match
        route_path = route.get("path")
        if route_path is not None:
            rp = route_path.strip("/")
            rp_parts = [] if not rp else rp.split("/")

            # Exact match
            if rp_parts == remaining_parts:
                return route

            # Prefix match for nested children
            if len(rp_parts) <= len(remaining_parts) and remaining_parts[:len(rp_parts)] == rp_parts:
                child_parts = remaining_parts[len(rp_parts):]
                children = route.get("children") or route.get("routes") or []
                for child in children:
                    matched = match_route(child, child_parts)
                    if matched is not None:
                        return matched
                # If no child matched but this route is a valid prefix and has an index/default child
                if not child_parts:
                    return route

        # Try children directly if present
        children = route.get("children") or route.get("routes") or []
        for child in children:
            matched = match_route(child, remaining_parts)
            if matched is not None:
                return matched

        return None

    # If route is a list, search each entry
    if isinstance(route, list):
        for item in route:
            matched = match_route(item, remaining_parts)
            if matched is not None:
                return matched
        return None

    # If route is a string, compare directly
    if isinstance(route, str):
        rp = route.strip("/")
        return route if (rp.split("/") if rp else []) == remaining_parts else None

    # Fallback: if route is some other object, return it only on empty path
    return route if not remaining_parts else None

