def _read_page(self, page: int) -> bytes:
    """Read a page directly from the main file."""
    offset = page * self._tree_conf.page_size
    self._fd.seek(offset, io.SEEK_SET)
    data = self._fd.read(self._tree_conf.page_size)
    return data

def perform_checkpoint(self, reopen_wal: bool = False):
    """Flush WAL contents into the main file."""
    # Write all WAL pages to the backing file.
    for page, data in self._wal.items():
        offset = page * self._tree_conf.page_size
        self._fd.seek(offset, io.SEEK_SET)
        self._fd.write(data)

    self._fd.flush()
    os.fsync(self._fd.fileno())

    # Reset WAL after checkpoint.
    self._wal.clear()

    if reopen_wal:
        self._wal.close()
        self._wal = WAL(self._filename, self._tree_conf.page_size)

def close(self):
    """Close file handles and flush pending changes."""
    self.perform_checkpoint(reopen_wal=False)
    self._wal.close()
    self._fd.close()
    self._dir_fd.close()

