import base64

def _decode(obj):
    if isinstance(obj, dict):
        # If this dict represents a base64-encoded value, decode it.
        if obj.get("$base64") is True and "encoded" in obj:
            encoded = obj["encoded"]
            if isinstance(encoded, str):
                try:
                    return base64.b64decode(encoded).decode("utf-8")
                except Exception:
                    # If decoding fails, leave the object unchanged.
                    return obj
            return obj

        return {k: _decode(v) for k, v in obj.items()}

    if isinstance(obj, list):
        return [_decode(v) for v in obj]

    return obj

