@wraps(f)
def wrapper(*args, **kwargs):
    global _retry_count, _in_retry

    # Prevent nested retry loops from interfering with each other.
    if _in_retry:
        return f(*args, **kwargs)

    _retry_count = 0
    _in_retry = True
    try:
        while True:
            try:
                return f(*args, **kwargs)
            except (AutoReconnect, OperationFailure, ServerSelectionTimeoutError, BulkWriteError) as e:
                _retry_count += 1
                _handle_error(f, e, _retry_count, **_get_host(args[0] if args else None))
            except DuplicateKeyError:
                # Duplicate key errors are not transient; re-raise immediately.
                raise
    finally:
        _in_retry = False

return wrapper

