if isinstance(o1, (int, float)) and isinstance(o2, (int, float)):
    diff = abs(o1 - o2)
    return diff <= max(atol, rtol * max(abs(o1), abs(o2)))

# Type mismatch for non-numeric values
if type(o1) != type(o2):
    return False

# Dict comparison
if isinstance(o1, dict):
    if o1.keys() != o2.keys():
        return False
    return all(are_equals(o1[k], o2[k], **kwargs) for k in o1)

# Sequence comparison
if isinstance(o1, (list, tuple)):
    if len(o1) != len(o2):
        return False
    return all(are_equals(a, b, **kwargs) for a, b in zip(o1, o2))

# Set comparison
if isinstance(o1, (set, frozenset)):
    if len(o1) != len(o2):
        return False
    # Sets are unordered; compare via exact equality first, then fallback
    return o1 == o2

# Fallback
return o1 == o2

