class WalELogger(object):
    def __init__(self, *args, **kwargs):
        self._logger = logging.getLogger(*args, **kwargs)

    @staticmethod
    def _fmt_structured(d):
        """Formats '{k1:v1, k2:v2}' => 'time=... pid=... k1=v1 k2=v2'

        Output is lexically sorted, *except* the time and pid always
        come first, to assist with human scanning of the data.
        """
        import os
        import time

        if d is None:
            d = {}

        # Start with required fields.
        items = [
            ("time", time.strftime("%Y-%m-%dT%H:%M:%S", time.gmtime())),
            ("pid", os.getpid()),
        ]

        # Add remaining fields in lexical order, excluding time/pid if present.
        for k in sorted(d.keys()):
            if k in ("time", "pid"):
                continue
            items.append((k, d[k]))

        def _fmt_val(v):
            if isinstance(v, bool):
                return "true" if v else "false"
            return str(v)

        return " ".join("%s=%s" % (k, _fmt_val(v)) for k, v in items)

