@classmethod
def int_to_script_bytes(class_, v):
    if v == 0:
        return b""

    is_negative = v < 0
    v = abs(v)

    result = bytearray()
    while v:
        result.append(v & 0xff)
        v >>= 8

    # If the most significant byte has the sign bit set, add a new byte
    # to avoid ambiguity with negative numbers.
    if result[-1] & 0x80:
        result.append(0x80 if is_negative else 0x00)
    elif is_negative:
        result[-1] |= 0x80

    return bytes(result)

