import sys

@contextmanager
def extend_sys_path(*paths):
    """Context manager to temporarily add paths to sys.path."""
    original_sys_path = list(sys.path)
    try:
        for path in paths:
            if path not in sys.path:
                sys.path.insert(0, path)
        yield
    finally:
        sys.path[:] = original_sys_path

