class SimplexTransform(RVTransform):
    name = "simplex"

    def forward(self, value, *inputs):
        # Map unconstrained real-valued inputs to the simplex via softmax.
        # This ensures positivity and unit-sum constraints.
        value = np.asarray(value)
        e = np.exp(value - np.max(value, axis=-1, keepdims=True))
        return e / np.sum(e, axis=-1, keepdims=True)

