def apply_backspaces(s):
    buf = []
    for ch in s:
        if ch == "\b":
            if buf:
                buf.pop()
        else:
            buf.append(ch)
    return "".join(buf)

for line in lines:
    # Preserve a trailing carriage return if it is the last character
    # of the final chunk, so the caller can concatenate more output later.
    if line.endswith("\r") and line == lines[-1]:
        current.append(line)
        continue

    current.append(line)
    chunk = "".join(current)

    # Handle carriage returns by keeping only the last segment after '\r'
    # (terminal-style overwrite behavior).
    chunk = chunk.split("\r")[-1]

    # Remove linefeed and apply backspaces.
    chunk = chunk.replace("\n", "")
    chunk = apply_backspaces(chunk)

    out.append(chunk)
    current = []

if current:
    # If we ended with a dangling carriage return, preserve it.
    return "".join(out) + "".join(current)

return "".join(out)

