def apply_jitter(value):
    if not jitter:
        return value
    # True behaves like 1.0
    j = 1.0 if jitter is True else float(jitter)
    if j >= 0:
        # value is the maximum; choose uniformly from [0, value]
        return random.uniform(0.0, value * j if j != 1.0 else value)
    else:
        # value is the minimum; choose uniformly from [value, value * (1 - j)]
        # for negative jitter, interpret magnitude as spread factor
        return random.uniform(value, value * (1.0 + abs(j)))

yielded = 0
while True:
    out = current if current < stop else stop
    yield apply_jitter(out)
    yielded += 1

    if remaining is not None and yielded >= remaining:
        break
    if current >= stop:
        if remaining is None:
            # default behavior: once stop is reached, keep yielding stop forever
            pass
        current = stop
    else:
        current *= factor
        if current > stop:
            current = stop

