def decorator(func):
    if not callable(func):
        raise TypeError("Expected a callable")

    try:
        import inspect
        sig = inspect.signature(func)
        params = sig.parameters.values()

        # Count required positional arguments
        required = [
            p for p in params
            if p.kind in (p.POSITIONAL_ONLY, p.POSITIONAL_OR_KEYWORD)
            and p.default is p.empty
        ]

        # If the function accepts *args, allow it as long as it can take at least arity
        has_varargs = any(p.kind == p.VAR_POSITIONAL for p in params)

        if not has_varargs and len(required) != arity:
            raise TypeError(
                f"Callable must accept exactly {arity} positional arguments"
            )
        if has_varargs and len(required) > arity:
            raise TypeError(
                f"Callable must accept at least {arity} positional arguments"
            )
    except (ValueError, TypeError):
        # If signature inspection fails, fall back to accepting the callable
        pass

    return func

return decorator

