@classmethod
def all_bootstraps(cls):
    '''Find all the available bootstraps and return them.'''
    import os
    import pkgutil
    import importlib

    bootstraps = []

    # Walk the bootstraps package and import all modules that contain
    # Bootstrap subclasses.
    package_name = cls.__module__.rsplit('.', 1)[0]
    package = importlib.import_module(package_name)

    for _, modname, ispkg in pkgutil.iter_modules(package.__path__):
        if ispkg:
            continue
        module = importlib.import_module('{}.{}'.format(package_name, modname))

        for obj_name in dir(module):
            obj = getattr(module, obj_name)
            if (
                isinstance(obj, type)
                and issubclass(obj, cls)
                and obj is not cls
                and getattr(obj, 'can_be_chosen_automatically', False)
            ):
                bootstraps.append(obj)

    return bootstraps

