@classmethod
def SPAWN_WITH_LOOP(cls, loop):
    if loop is None:
        loop = asyncio.get_event_loop()

    def create_wrapper(f):
        if not hasattr(f, "__call__"):
            raise TypeError("must be callable, got {!r}".format(f))
        if not asyncio.iscoroutinefunction(f):
            raise TypeError("must be a coroutine function, got {!r}".format(f))
        return functools.partial(cls._spawn_wrapper, f, loop)

    return create_wrapper

async def send_and_wait_for(xmlstream, send, wait_for,
                            timeout=None,
                            cb=None):
    """
    Send an XML stanza and wait until a matching stanza is received.

    :param xmlstream: XML stream object
    :param send: stanza to send
    :param wait_for: callable or matcher used to decide when to stop waiting
    :param timeout: optional timeout in seconds
    :param cb: optional callback invoked for each received stanza
    :return: the stanza that matched wait_for
    """
    loop = asyncio.get_event_loop()
    fut = loop.create_future()

    def _handler(stanza):
        try:
            if cb is not None:
                cb(stanza)
            if wait_for(stanza):
                if not fut.done():
                    fut.set_result(stanza)
        except Exception as e:
            if not fut.done():
                fut.set_exception(e)

    # Register temporary handler/listener
    xmlstream.add_handler(_handler)

    try:
        xmlstream.send(send)
        if timeout is not None:
            return await asyncio.wait_for(fut, timeout)
        return await fut
    finally:
        # Best-effort cleanup
        try:
            xmlstream.remove_handler(_handler)
        except Exception:
            pass

