def _make_handler():
    def _handler(*args, **kwargs):
        if future.done():
            return

        # Only zero or one positional argument and no kwargs are supported.
        if kwargs or len(args) > 1:
            return

        if len(args) == 0:
            future.set_result(None)
            return

        value = args[0]
        if isinstance(value, BaseException):
            future.set_exception(value)
        else:
            future.set_result(value)

    return _handler

