if not arr:
    raise IndexError("empty array")

if x < arr[0] or x >= arr[-1]:
    raise IndexError("query outside array values")

lo = 0
hi = len(arr) - 1

while lo < hi:
    # If x is exactly at the upper bound, the answer is the previous index.
    if arr[hi] == arr[lo]:
        break

    # Interpolation estimate
    pos = lo + (x - arr[lo]) * (hi - lo) // (arr[hi] - arr[lo])

    # Clamp to valid range just in case of integer arithmetic edge cases
    if pos < lo:
        pos = lo
    elif pos > hi:
        pos = hi

    if arr[pos] <= x:
        if pos + 1 <= hi and x < arr[pos + 1]:
            return pos
        lo = pos + 1
    else:
        hi = pos - 1

# Fallback: lo should be the insertion point
if lo > 0 and arr[lo] > x:
    return lo - 1
return lo

