@classmethod
def infer_extractor_format(cls, path: Union[Path, str]) -> str:  # <Added version="2.4.0"/>
    magic_number_length = cls._get_magic_number_max_length()
    magic_number = cls._read_magic_number(path, magic_number_length)

    if not magic_number:
        return ""

    for extractor_format, extractor in cls.extractors.items():
        if not issubclass(extractor, MagicNumberBaseExtractor):
            continue

        for extractor_magic_number in extractor.magic_numbers:
            if magic_number.startswith(extractor_magic_number):
                return extractor_format

    return ""

# Implementation based on https://docs.python.org/3/library/dataclasses.html#dataclasses.asdict
from collections.abc import Mapping, Sequence

def _asdict_inner(value):
    if isinstance(value, Mapping):
        return type(value)((_asdict_inner(k), _asdict_inner(v)) for k, v in value.items())
    elif isinstance(value, tuple) and hasattr(value, "_fields"):  # namedtuple
        return type(value)(*(_asdict_inner(v) for v in value))
    elif isinstance(value, Sequence) and not isinstance(value, (str, bytes, bytearray)):
        return type(value)(_asdict_inner(v) for v in value)
    elif hasattr(value, "__dict__"):
        return {k: _asdict_inner(v) for k, v in value.__dict__.items()}
    else:
        return value

return _asdict_inner(obj)

