class MacVendorDB:
    """Maps from MACs to Manufacturers via the IEEE Organizationally Unique Identifier (oui) list."""
    def __init__(self, oui_file=os.path.join(os.path.dirname(os.path.abspath(__file__)), 'oui.txt')):
        self.db = {}
        with open(oui_file, 'r') as f:
            for line in f.readlines():
                mac, vendor = line.split('=', maxsplit=1)
                self.db[mac] = vendor.strip()

    def lookup(self, mac):
        """MAC -> Manufacturer ('48:AD:08:AA:BB:CC' -> 'HUAWEI TECHNOLOGIES CO.,LTD')"""
        if not mac:
            return None

        # Normalize MAC and use only the OUI prefix (first 3 octets)
        mac = mac.upper().replace('-', ':')
        oui = ':'.join(mac.split(':')[:3])

        return self.db.get(oui)

class UnhideCommand(CommandStrategy):
    def execute(self):
        """
        Implements the command `unhide` which restores a unit definition that
        was hidden from the AST.
        """
        if len(self.command_tokens) < 3:
            self.print_wrapper.error_log(
                "Missing some arguments\nUsage: " + self.usage_str
            )
            return

        unit_type = CommandStrategy.get_unit_type_from_str(self.command_tokens[1])
        if unit_type is None:
            self.print_wrapper.error_log(
                "Unknown unit type: '" + str(self.command_tokens[1]) + "'."
            )
            return

        unit_regex = self.get_regex_name(self.command_tokens[2])
        if unit_regex is None:
            try:
                [unit_name, variation_name] = CommandStrategy.split_exact_unit_name(
                    self.command_tokens[2]
                )
            except SyntaxError:
                self.print_wrapper.error_log(
                    "Unit identifier couldn't be interpreted. "
                    "Did you mean to escape some hashtags '#'?")
                return

            if variation_name is None:
                try:
                    unit = HideCommand.stored_units[unit_type.name].pop(unit_name)
                    AST.get_or_create()[unit_type][unit_name] = unit
                    self.print_wrapper.write(
                        unit_type.name.capitalize() + " '" + unit_name + \
                        "' was successfully unhidden."
                    )
                except KeyError:
                    self.print_wrapper.write(
                        unit_type.name.capitalize() + " '" + unit_name + \
                        "' was not hidden."
                    )
            else:
                try:
                    variation_rules = \
                        HideCommand.stored_variations[unit_type.name][unit_name].pop(
                            variation_name
                        )
                    AST.get_or_create()[unit_type][unit_name]._variation_rules[
                        variation_name
                    ] = variation_rules
                    self.print_wrapper.write(
                        "Variation '" + variation_name + "' of " + \
                        unit_type.name + " '" + unit_name + \
                        "' was successfully unhidden."
                    )
                except KeyError:
                    self.print_wrapper.write(
                        "Variation '" + variation_name + "' of " + \
                        unit_type.name + " '" + unit_name + \
                        "' was not hidden."
                    )
        else:
            count = 0
            for unit_name in self.next_matching_unit_name(unit_type, unit_regex):
                if unit_name in HideCommand.stored_units[unit_type.name]:
                    unit = HideCommand.stored_units[unit_type.name].pop(unit_name)
                    AST.get_or_create()[unit_type][unit_name] = unit
                    count += 1
                    self.print_wrapper.write(
                        unit_type.name.capitalize() + " '" + unit_name + \
                        "' was successfully unhidden."
                    )
            if count == 0:
                self.print_wrapper.write("No " + unit_type.name + " matched.")

        self.finish_execution()

