class DefaultStrategy(Strategy):
    @classmethod
    def get_worker_count(
        cls,
        runnable_class: t.Type[Runnable],
        resource_request: dict[str, t.Any] | None,
        workers_per_resource: int | float,
    ) -> int:
        # Default to a single worker if no resource request is provided.
        if not resource_request:
            return 1

        # Prefer CPU if requested; otherwise fall back to the first requested resource.
        resource_name = "cpu" if "cpu" in resource_request else next(iter(resource_request))
        requested = resource_request.get(resource_name, 1)

        try:
            requested_count = float(requested)
        except (TypeError, ValueError):
            requested_count = 1.0

        worker_count = int(requested_count * workers_per_resource)

        # Always ensure at least one worker.
        return max(worker_count, 1)

