class _HMAC(MAC):
    def __init__(self, key: bytes, digestmod, hash_size: int):
        super().__init__(key, hash_size)
        self._digestmod = digestmod

    def sign(self, seq: int, packet: bytes) -> bytes:
        mac = hmac.new(self._key, digestmod=self._digestmod)
        mac.update(UInt32(seq))
        mac.update(packet)
        return mac.digest()[:self._hash_size]

    def verify(self, seq: int, packet: bytes, sig: bytes) -> bool:
        return hmac.compare_digest(self.sign(seq, packet), sig)

if alg in (b"hmac-md5", b"hmac-md5-96"):
