if alg in (b"hmac-sha1", b"hmac-sha1-96"):
    return _HMAC(key, sha1, 12 if alg.endswith(b"-96") else 20)
if alg == b"hmac-sha2-224":
    return _HMAC(key, sha224, 28)
if alg == b"hmac-sha2-256":
    return _HMAC(key, sha256, 32)
if alg == b"hmac-sha2-384":
    return _HMAC(key, sha384, 48)
if alg == b"hmac-sha2-512":
    return _HMAC(key, sha512, 64)

class _UMAC64(MAC):
    def sign(self, seq: int, packet: bytes) -> bytes:
        return umac64(self._key, UInt32(seq) + packet)

    def verify(self, seq: int, packet: bytes, sig: bytes) -> bool:
        return hmac.compare_digest(self.sign(seq, packet), sig)

class _UMAC128(MAC):
    def sign(self, seq: int, packet: bytes) -> bytes:
        return umac128(self._key, UInt32(seq) + packet)

    def verify(self, seq: int, packet: bytes, sig: bytes) -> bool:
        return hmac.compare_digest(self.sign(seq, packet), sig)

if alg == b"umac-64":
