@stored_property
def dependencies(self):
    """Run's the files' linker iteratively and returns a set of all library dependencies."""
    dependencies = set()
    to_process = [self]
    seen = set()

    while to_process:
        file_object = to_process.pop()
        if file_object in seen:
            continue
        seen.add(file_object)

        try:
            direct_dependencies = file_object.find_direct_dependencies()
        except Exception as exc:
            raise DependencyDetectionError(
                'Failed to detect dependencies for "%s": %s' % (file_object.path, exc)
            )

        for dependency in direct_dependencies:
            if dependency not in dependencies:
                dependencies.add(dependency)
                # Recurse into ELF binaries only.
                if isinstance(dependency, Elf):
                    to_process.append(dependency)

    return dependencies

