@staticmethod
def fmt_logline(msg, detail=None, hint=None, structured=None):
    """Format a log line with optional detail, hint, and structured data.

    The output is a single human-readable string. If structured data is
    provided, it is formatted using `_fmt_structured()` and appended to the
    message.
    """
    parts = [str(msg)]

    if detail is not None:
        parts.append("detail=" + str(detail))

    if hint is not None:
        parts.append("hint=" + str(hint))

    if structured is not None:
        if isinstance(structured, dict):
            parts.append(WalELogger._fmt_structured(structured))
        else:
            parts.append(str(structured))

    return " ".join(parts)

@staticmethod
def from_jwk(jwk: str | JWKDict) -> bytes:
    if isinstance(jwk, str):
        jwk = json.loads(jwk)

    if not isinstance(jwk, dict):
        raise InvalidKeyError("JWK must be a JSON object or a JSON string.")

    if jwk.get("kty") != "oct":
        raise InvalidKeyError("Not an HMAC key (kty must be 'oct').")

    if "k" not in jwk:
        raise InvalidKeyError("JWK does not contain key material 'k'.")

    return base64url_decode(force_bytes(jwk["k"]))

