@property
def precedence(self):
    """
    Return a precedence level from 0-3 for the media type given how specific it is.
    """
    # 0: */*
    if self.main_type == '*' and self.sub_type == '*':
        return 0

    # 1: type/*
    if self.main_type != '*' and self.sub_type == '*':
        return 1

    # 2: */subtype
    if self.main_type == '*' and self.sub_type != '*':
        return 2

    # 3: type/subtype
    return 3

