class ReilParser(object):

    """Reil Instruction Parser."""

    def __init__(self):

        # A parsing cache. Each parsed instruction is cached to improve
        # performance.
        self._cache = {}

    def parse(self, instrs):
        """Parse an IR instruction.
        """
        # Accept either a single instruction string or an iterable of them.
        if isinstance(instrs, (str, bytes)):
            instrs = [instrs]

        parsed_instrs = []

        for instr in instrs:
            if instr in self._cache:
                parsed_instrs.append(copy.deepcopy(self._cache[instr]))
                continue

            parsed = instruction.parseString(instr, parseAll=True)[0]
            self._cache[instr] = copy.deepcopy(parsed)
            parsed_instrs.append(parsed)

        return parsed_instrs

