    resp = self.table.connection.batch_write_item(batch_data)
    self._unprocessed = []

    self.handle_unprocessed(resp)

    config: Settings, df: pd.DataFrame, summary: dict
) -> Optional[pd.DataFrame]:
    """Compute Cramer's V correlation matrix for categorical variables."""
    if not config.correlations.cramers.enabled:
        return None

    columns = summary.get("categorical", [])
    if not columns:
        return None

    # Keep only columns that exist in the dataframe
    columns = [col for col in columns if col in df.columns]
    if len(columns) < 2:
        return None

    correlation_matrix = pd.DataFrame(
        np.eye(len(columns)), index=columns, columns=columns, dtype=float
    )

    for i, col1 in enumerate(columns):
        for j in range(i + 1, len(columns)):
            col2 = columns[j]

            confusion_matrix = pd.crosstab(df[col1], df[col2])

            if confusion_matrix.empty:
                corr = 0.0
            else:
                corr = _cramers_corrected_stat(
                    confusion_matrix, correction=config.correlations.cramers.correction
                )

            correlation_matrix.loc[col1, col2] = corr
            correlation_matrix.loc[col2, col1] = corr

    return correlation_matrix

