@contextlib.contextmanager
def assertLoopErrorHandlerCalled(self, msg_re: str):
    """
    Assert that the event loop's exception handler is called with a
    message matching ``msg_re`` while the context is active.
    """
    called = []

    def handler(loop, context):
        called.append(context)
        self.loop_exception_handler(loop, context)

    old_handler = self.loop.get_exception_handler()
    self.loop.set_exception_handler(handler)
    try:
        yield
    finally:
        self.loop.set_exception_handler(old_handler)

        if not called:
            self.fail(
                'expected loop exception handler to be called, but it was not'
            )

        messages = []
        for i, context in enumerate(called):
            messages.append(self._format_loop_exception(context, i + 1))

        combined = '\n'.join(messages)
        if not re.search(msg_re, combined):
            self.fail(
                'loop exception handler was called, but no message matched '
                f'{msg_re!r}:\n{combined}'
            )

return self._introspect_all_indexes(
