class IntStreamer(object):

    @classmethod
    def int_from_script_bytes(class_, s, require_minimal=False):
        if not s:
            return 0

        # Bitcoin Script numbers are little-endian signed-magnitude integers.
        # The most significant byte's highest bit is the sign bit.
        v = bytearray(s)

        negative = (v[-1] & 0x80) != 0
        if negative:
            v[-1] &= 0x7f

        # Minimal encoding checks
        if require_minimal:
            # No unnecessary leading zero bytes.
            if len(v) > 1:
                # If the most significant byte is zero, then the sign bit of the
                # next byte must be set, otherwise the encoding is non-minimal.
                if (v[-1] == 0) and ((v[-2] & 0x80) == 0):
                    raise ScriptError("non-minimally encoded script number", "SCRIPT_ERR_MINIMALDATA")

        result = 0
        for i, b in enumerate(v):
            result |= b << (8 * i)

        if negative:
            result = -result

        return result

