def _download_to_fileob(self, output_file, num_chunks, chunk_size,
                        verify_hashes, retry_exceptions):
    for chunk_num in range(num_chunks):
        start = chunk_num * chunk_size
        end = min(start + chunk_size - 1, self.archive_size - 1)
        byte_range = (start, end)

        attempts = 0
        while True:
            try:
                response = self.get_output(byte_range=byte_range,
                                           validate_checksum=verify_hashes)
                output_file.write(response.read())
                break
            except retry_exceptions:
                attempts += 1
                if attempts >= 3:
                    raise

