class PrevalenceCounter:
    def __init__(self):
        self.keyword_counts = defaultdict(int)
        self.name_counts = defaultdict(int)

    def update(self, text):
        if not text:
            return

        # Count words in a case-insensitive way
        words = re.findall(r"\b\w+\b", text.lower())

        for word in words:
            self.keyword_counts[word] += 1

            # Treat capitalized words as names when possible
            # (use original text tokens for this check)
        original_words = re.findall(r"\b\w+\b", text)
        for word in original_words:
            if word[:1].isupper():
                self.name_counts[word] += 1

