@cached_property
def document(self):
    paragraphs = []
    lines = self._text.splitlines()

    current_heading = []
    current_paragraph = []

    def flush_paragraph():
        nonlocal current_heading, current_paragraph
        if current_heading or current_paragraph:
            paragraphs.append(
                Paragraph(
                    headings=[Sentence(" ".join(current_heading))] if current_heading else [],
                    sentences=[Sentence(" ".join(current_paragraph))] if current_paragraph else [],
                )
            )
            current_heading = []
            current_paragraph = []

    for line in lines:
        stripped = line.strip()

        if not stripped:
            flush_paragraph()
            continue

        # A line in ALL UPPER CASE is treated as a heading.
        if stripped == stripped.upper() and any(ch.isalpha() for ch in stripped):
            # If we already have paragraph text, start a new paragraph.
            if current_paragraph:
                flush_paragraph()
            current_heading.append(stripped)
        else:
            current_paragraph.append(stripped)

    flush_paragraph()

    return Document(paragraphs)

