        if isinstance(spec, str):
            spec = spec.strip()
            if spec.endswith("m"):
                value = spec[:-1].strip()
                try:
                    return float(value) / 1000.0
                except ValueError as e:
                    raise BentoMLConfigException(
                        f"Invalid cpu resource specification: {spec!r}"
                    ) from e

            try:
                return float(spec)
            except ValueError as e:
                raise BentoMLConfigException(
                    f"Invalid cpu resource specification: {spec!r}"
                ) from e

        raise BentoMLConfigException(
            f"Invalid cpu resource specification: {spec!r}"
        )

