if mode == 0:
    # Absolute seek from start
    if pos < 0:
        raise ValueError("negative seek position {}".format(pos))
    self.buffer.seek(0)
    self._tell = 0
    if pos:
        self._tell = self._traverse_codepoints(0, pos)
    return self._tell

elif mode == 1:
    # Relative seek from current position
    if pos == 0:
        return self._tell
    if pos > 0:
        self._tell = self._traverse_codepoints(self._tell, pos)
        return self._tell
    else:
        # For negative relative seeks, rebuild from start
        target = self._tell + pos
        if target < 0:
            raise ValueError("negative seek position {}".format(target))
        self.buffer.seek(0)
        self._tell = 0
        if target:
            self._tell = self._traverse_codepoints(0, target)
        return self._tell

elif mode == 2:
    # Seek from end
    if pos > 0:
        raise ValueError("can't seek past end with SEEK_END")
    # Determine total length in codepoints by decoding the whole buffer
    self.buffer.seek(0)
    data = self.buffer.read()
    text = data.decode('utf-8')
    target = len(text) + pos
    if target < 0:
        raise ValueError("negative seek position {}".format(target))
    self.buffer.seek(0)
    self._tell = 0
    if target:
        self._tell = self._traverse_codepoints(0, target)
    return self._tell

else:
    raise ValueError("invalid whence ({})".format(mode))

@classmethod
def get_distrust_timeline(
    cls, verified_certificate_chain: List[Certificate]
) -> Optional[SymantecDistrustTimelineEnum]:
    # Symantec distrust only applies to chains anchored in a Symantec root / managed CA
    # or one of the known exceptions.
    if not verified_certificate_chain:
        return None

    # Check whether any certificate in the chain matches a known Symantec CA key.
    # The chain is typically leaf -> intermediate(s) -> root, but we inspect all certs.
    for certificate in verified_certificate_chain:
        pubkey_sha256 = binascii.hexlify(get_public_key_sha256(certificate)).decode("ascii")

        if pubkey_sha256 in cls._CA_KEYS_WHITELIST:
            # Whitelisted Symantec roots / exceptions are not distrusted.
            return None

        if pubkey_sha256 in cls._CA_KEYS_BLACKLIST:
            # Symantec roots are distrusted starting in March 2018.
            return SymantecDistrustTimelineEnum.MARCH_2018

    return None

