@classmethod
def parse_server_string(cls, server_str: str) -> Tuple[str, Optional[str], Optional[int]]:
    # Extract ip from target
    server_str = server_str.strip()

    if not server_str:
        raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)

    host: str
    ip: Optional[str] = None
    port: Optional[int] = None

    # Handle optional "{ip}" suffix
    if "{" in server_str:
        if not server_str.endswith("}"):
            raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
        server_str, ip = server_str[:-1].split("{", 1)
        ip = ip.strip() or None

    # IPv6 in brackets: [::1]:8080
    if server_str.startswith("["):
        end = server_str.find("]")
        if end == -1:
            raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
        host = server_str[1:end]
        remainder = server_str[end + 1 :]
        if remainder:
            if not remainder.startswith(":"):
                raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
            port_str = remainder[1:]
            if not port_str:
                raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
            try:
                port = int(port_str)
            except ValueError:
                raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)
    else:
        # Split on the last colon so IPv6 without brackets can still be handled
        # only when there is a single port separator at the end.
        if ":" not in server_str:
            raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)

        host_part, port_str = server_str.rsplit(":", 1)
        if not host_part or not port_str:
            raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)

        host = host_part
        try:
            port = int(port_str)
        except ValueError:
            raise ValueError(cls.SERVER_STRING_ERROR_BAD_PORT)

    return host, ip, port

