class Unreader(object):
    def __init__(self):
        self.buf = io.BytesIO()

    def chunk(self):
        raise NotImplementedError()

    def read(self, size=None):
        # Read all available data if size is not specified
        if size is None:
            chunks = [self.buf.read()]
            while True:
                data = self.chunk()
                if not data:
                    break
                chunks.append(data)
            return b"".join(chunks)

        # Read exactly `size` bytes if possible
        out = bytearray()

        # First consume from the internal buffer
        buf_data = self.buf.read(size)
        out.extend(buf_data)

        while len(out) < size:
            data = self.chunk()
            if not data:
                break
            need = size - len(out)
            out.extend(data[:need])
            # Save any extra bytes back into the buffer
            if len(data) > need:
                self.buf = io.BytesIO(data[need:])
                break

        return bytes(out)

