def get_invocation_str(self, with_annotations=True):
    parts = []

    # positional args
    for i, arg in enumerate(self.args):
        s = arg
        if with_annotations and self.annotations and arg in self.annotations:
            s += ': %s' % self.annotations[arg]
        if self.defaults:
            default_offset = len(self.args) - len(self.defaults)
            if i >= default_offset:
                default = self.defaults[i - default_offset]
                s += '=%r' % default
        parts.append(s)

    # *args
    if self.varargs:
        parts.append('*%s' % self.varargs)
    elif self.kwonlyargs:
        # bare * to indicate keyword-only args
        parts.append('*')

    # keyword-only args
    for arg in self.kwonlyargs:
        s = arg
        if with_annotations and self.annotations and arg in self.annotations:
            s += ': %s' % self.annotations[arg]
        if self.kwonlydefaults and arg in self.kwonlydefaults:
            s += '=%r' % self.kwonlydefaults[arg]
        parts.append(s)

    # **kwargs
    if self.varkw:
        parts.append('**%s' % self.varkw)

    return ', '.join(parts)

