async def peek(self, size=-1):
    """Return up to ``size`` bytes without consuming them.

    If ``size`` is negative or omitted, return all currently available
    buffered data plus any data that can be read from the source without
    permanently consuming it.
    """
    if size is None:
        size = -1

    if size == 0:
        return b''

    # If we already have enough buffered data, return it directly.
    available = self._buffer_len - self._buffer_pos
    if size > 0 and available >= size:
        return self._buffer[self._buffer_pos : self._buffer_pos + size]

    # Otherwise, read from the current view of the stream without
    # permanently consuming more than requested.
    if size < 0:
        return await self._read_from(self._iter_with_buffer())
    return await self._read_from(self._iter_with_buffer(size_hint=size), size=size)

