@property
def relative_datetime(self):
    """Return human-readable relative time string."""
    now = datetime.now(tzlocal())
    delta = now - self.created_at

    # Future times
    if delta.total_seconds() < 0:
        delta = -delta
        suffix = "from now"
    else:
        suffix = "ago"

    seconds = int(delta.total_seconds())

    if seconds < 60:
        return "just now" if suffix == "ago" else "in a few seconds"
    elif seconds < 3600:
        minutes = seconds // 60
        return f"{minutes} minute{'s' if minutes != 1 else ''} {suffix}"
    elif seconds < 86400:
        hours = seconds // 3600
        return f"{hours} hour{'s' if hours != 1 else ''} {suffix}"
    elif seconds < 604800:
        days = seconds // 86400
        return f"{days} day{'s' if days != 1 else ''} {suffix}"
    else:
        return self.created_at.strftime("%Y-%m-%d")

