class SourceProcessor:
    """
    Pre-process comments like #!viztracer: log_instant("event")
    """

    def process(self, source: Any):
        if source is None:
            return source

        # Normalize to a list of lines while preserving line endings
        if isinstance(source, bytes):
            text = source.decode("utf-8")
            return self.process(text).encode("utf-8")

        if not isinstance(source, str):
            return source

        lines = source.splitlines(keepends=True)
        processed_lines = []

        for line in lines:
            stripped = line.lstrip()
            indent = line[: len(line) - len(stripped)]

            marker = "#!viztracer:"
            if stripped.startswith(marker):
                # Replace the directive comment with the Python code after it
                replacement = stripped[len(marker):].lstrip()
                # Preserve original indentation
                processed_lines.append(indent + replacement)
                # Ensure the replacement keeps a newline if the original line had one
                if line.endswith("\n") and not processed_lines[-1].endswith("\n"):
                    processed_lines[-1] += "\n"
            else:
                processed_lines.append(line)

        return "".join(processed_lines)

