class MusicSource:
    """
        Music source proxy object
    """

    def __init__(self):
        self.logger = logging.getLogger(__name__)

    def search(self, keyword, sources_list) -> list:
        if not keyword or not str(keyword).strip():
            raise ParameterError("keyword cannot be empty")

        if not sources_list:
            raise ParameterError("sources_list cannot be empty")

        results = []
        for source in sources_list:
            if source is None:
                continue

            # Support either a source object with a search method or a callable
            try:
                if hasattr(source, "search") and callable(source.search):
                    data = source.search(keyword)
                elif callable(source):
                    data = source(keyword)
                else:
                    raise ParameterError(f"Invalid source: {source}")
            except Exception as e:
                self.logger.exception("Search failed for source %s", source)
                continue

            if data:
                if isinstance(data, list):
                    results.extend(data)
                else:
                    results.append(data)

        return results

