@classmethod
def for_system(cls) -> "FixedOffset":
    """Return a FixedOffset instance for the current working timezone and
    DST conditions.
    """
    import time

    # Determine the current local offset from UTC, including DST if active.
    if time.daylight and time.localtime().tm_isdst > 0:
        offset_seconds = -time.altzone
    else:
        offset_seconds = -time.timezone

    return cls(offset_seconds / 60)

import math
from collections import defaultdict

if self.prior_probs is None or self.trans_probs is None:
    raise MsticpyException("Model has not been trained. Call `train()` first.")

def _session_tokens(session):
    toks = list(session)
    if use_start_end_tokens:
        toks = [self.start_token] + toks + [self.end_token]
    return toks

def _token_prob(tok):
    return self.prior_probs.get(tok, self.prior_probs.get(self.unk_token, 0.0))

def _pair_prob(a, b):
    return self.trans_probs.get(a, {}).get(b, self.trans_probs.get(a, {}).get(self.unk_token, 0.0))

self.session_likelihoods = []
self.session_geomean_likelihoods = []
self.rare_windows = defaultdict(list)
self.rare_window_likelihoods = defaultdict(list)
self.rare_windows_geo = defaultdict(list)
self.rare_window_likelihoods_geo = defaultdict(list)

for idx, session in enumerate(self.sessions):
    toks = _session_tokens(session)

    # Token likelihoods
    tok_probs = [_token_prob(tok) for tok in toks]
    self.session_likelihoods.append(tok_probs)

    # Geometric mean of token likelihoods
    if tok_probs and all(p > 0 for p in tok_probs):
        self.session_geomean_likelihoods.append(
            math.exp(sum(math.log(p) for p in tok_probs) / len(tok_probs))
        )
    else:
        self.session_geomean_likelihoods.append(np.nan)

    # Sliding windows of length 2 and 3
    for win_len in (2, 3):
        if len(toks) < win_len:
            self.rare_windows[win_len].append(np.nan)
            self.rare_window_likelihoods[win_len].append(np.nan)
            self.rare_windows_geo[win_len].append(np.nan)
            self.rare_window_likelihoods_geo[win_len].append(np.nan)
            continue

        window_liks = []
        window_geos = []

        for i in range(len(toks) - win_len + 1):
            window = toks[i : i + win_len]

            # Likelihood of a window as product of token probs and transition probs
            lik = _token_prob(window[0])
            for j in range(1, len(window)):
                lik *= _pair_prob(window[j - 1], window[j])

            window_liks.append(lik)

            # Geometric mean of the probabilities used in the window
            probs_used = [_token_prob(window[0])] + [
                _pair_prob(window[j - 1], window[j]) for j in range(1, len(window))
            ]
            if probs_used and all(p > 0 for p in probs_used):
                window_geos.append(
                    math.exp(sum(math.log(p) for p in probs_used) / len(probs_used))
                )
            else:
                window_geos.append(np.nan)

        # Rarest window = minimum likelihood
        if window_liks:
            min_idx = int(np.nanargmin(window_liks))
            self.rare_windows[win_len].append(toks[min_idx : min_idx + win_len])
            self.rare_window_likelihoods[win_len].append(window_liks[min_idx])
        else:
            self.rare_windows[win_len].append(np.nan)
            self.rare_window_likelihoods[win_len].append(np.nan)

        if window_geos and not all(np.isnan(v) for v in window_geos):
            min_geo_idx = int(np.nanargmin(window_geos))
            self.rare_windows_geo[win_len].append(toks[min_geo_idx : min_geo_idx + win_len])
            self.rare_window_likelihoods_geo[win_len].append(window_geos[min_geo_idx])
        else:
            self.rare_windows_geo[win_len].append(np.nan)
            self.rare_window_likelihoods_geo[win_len].append(np.nan)

